@DubboReference(version = "1.0.0", check = false, timeout = 5000)
private HealthReportAPI healthReportAPI;

public Result<UploadReportResponse> uploadReport(UploadReportRequest request) {
    try {
        return Result.success(healthReportAPI.uploadReport(request));
    } catch (RpcException e) {
        log.error("RPC call failed", e);
        return Result.fail("Service unavailable");
    }
}

