RefreshTokenRequest refreshReq = new RefreshTokenRequest();
refreshReq.setRefreshToken(loginResp.getData().getRefreshToken());
Result<RefreshTokenResponse> newTokens = authClient.post("/auth/refresh", refreshReq);

